VALUES
  ('bookkeeper-moex-00287', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '美國A公司在我國境內無固定營業場所及營業代理人，其與我國B公司簽訂技術合約，A公司指派 居住於美國之員工甲於112年3月1日出差至我國為B公司提供技術服務，甲於出差期間取得A公 司給付之薪資200萬元，B公司並給付A公司技術服務報酬300萬元，甲於同年4月30日返回美 國，下列敘述何者正確？', '["甲應在離境前就取得A公司之薪資向國稅局辦理申報納稅", "B公司應就給付A公司之技術服務報酬300萬元辦理扣繳申報", "A公司應就取得之技術服務報酬300萬元，委託我國境內營利事業向國稅局辦理申報納稅", "B公司應就甲取得之薪資200萬元辦理扣繳申報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00288', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國居住者個人甲112年取得收入如下：①薪資收入200萬元  ②統一發票中獎獎金1千萬元  ③借', '["檢舉賄選取得法務部獎金10萬元  ⑤A銀行給付存款利息12萬元 ⑥出售適用房地合一稅制之房屋、土地之利得250萬元  ⑦取得美國債券利息20萬元。依所得稅法 規定，112年度綜合所得總額及儲蓄投資特別扣除額金額各為何？", "196.3萬元、17萬元", "227萬元、17萬元", "196.3萬元、12萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00289', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', 'A公司111年交易情形如下：①以1萬元向農民購入10公斤玉米  ②給付會計師110年度所得稅結', '["將自產轎車1輛（成本80萬元）提供員工尾牙抽獎", "給付B公司權 利金120萬元並取得統一發票。依所得稅法相關法規，何者屬應扣繳之所得？", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00290', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', 'A公司為貿易業，111年聘僱甲員工，每月薪資6萬元（內含甲自願提繳勞工退休金3,600元），共12 個月，每月另給付伙食費5,000元，年底給付1個月年終獎金，並以甲為受益人為其投保團體人壽保 險，每年負擔保險費3,000元，甲當年應公司要求出差2次，共支領差旅費4萬元，A公司應申報甲 員工111年度薪資所得扣繳憑單之給付總額為何？', '["769,000元", "771,000元", "796,800元", "811,000元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00291', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法規定，下列何種所得免納所得稅？①個人出售上市公司股票所得  ②因繼承而取得之', '["國立大學校長所領主管特支費", "上市公司幹部所領主管特支費  ⑤個人接受公司贈與 所取得之財產  ⑥出售未發行股票之股權憑證所獲所得", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00292', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法及相關法規規定，下列有關扣繳義務人之敘述，何者正確？', '["依我國公司法成立之公司分配股利予非中華民國境內居住之個人股東，扣繳義務人為公司", "我國居住者個人承租房屋居住所給付房東之租金，扣繳義務人為承租之個人", "律師事務所每月給付員工之薪資，扣繳義務人為該事務所", "有限合夥事業分配盈餘予總機構在我國境外之營利事業股東，扣繳義務人為有限合夥事業負責人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00293', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '總機構在我國境外之營利事業，在我國境內經營下列何種業務，其成本費用分攤計算困難者，可向財', '["承包營建工程", "經營國際運 輸", "出租機器設備", "提供技術服務  ⑤出租影片"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00294', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法有關綜合所得稅之免稅額規定，下列何者得列報為受扶養親屬？', '["就讀軍校之已成年子女", "已成年，在補習準備國考的子女", "服役中之已成年子女", "大學畢業被資遣，目前待業中的子女"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00295', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國居住者個人甲112年所得資料如下：①申報112年度綜合所得淨額450萬元，一般所得稅額95.8', '["直接持有符合受控外國企業制度之中華民國境外關係企業股份10%，該關係企業當年度盈餘 換算新臺幣為800萬元", "交易在證券交易所上市之股票，利得50萬元", "對政府捐贈800萬元（實 物及現金各400萬元）全數申報列舉扣除額  ⑤取得美國有價證券利息10萬元。依所得基本稅額條 例相關規定，112年度基本所得額及基本稅額金額各為何？", "490萬元、0萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00296', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得基本稅額條例規定，在計算營利事業基本所得額時，下列何者須計入？①依國際金融業務條例', '["免稅之土地交易所得", "依所得稅法規定不計入所得額課稅之股利收入", "依 企業併購法規定之免稅所得  ⑤依所得稅法規定停徵所得稅之證券交易所得", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00297', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國居住者個人甲及乙於 110 年合夥成立 A 商號，由甲負責經營，因每月銷售額未達使用統一發票 標準而經核定為小規模營業人並採查定課徵營業稅，111年均達營業稅起徵點，下列有關A商號及合 夥人相關課稅情形，何者正確？', '["甲應於112年5月辦理A商號111年度營利事業所得稅結算申報，惟無須計算及繳納稅額", "乙於112年2月取得A商號111年度之盈餘，應併入其112年度綜合所得總額課稅", "A商號於111年購買營業上使用之貨物或勞務，取得載有營業稅額之憑證，並依規定申報者，稽徵 機關應按其進項稅額10%，在查定稅額內扣減", "A商號111年出售適用房地合一稅制之房屋、土地，其交易所得應計入該商號之所得額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00298', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '荷蘭公司與我國甲公司簽有顧問合約，不定期選派工程師到我國協助離岸風電相關業務，有關我國營 業稅之徵免規定為何？', '["屬於境外銷售勞務，不課營業稅", "屬於在我國境內銷售勞務，要課營業稅，由該工程師負責繳納", "屬於在我國境內銷售勞務，但因工程師不是營業人，故不課營業稅", "屬於在我國境內銷售勞務，要課營業稅，由甲公司負責繳納"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00299', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '中華民國境內無固定營業場所之外國營利事業之營業稅稽徵規定，下列敘述何者錯誤？', '["外國營利事業銷售勞務予我國境內營業人者，以買受人為營業稅納稅義務人", "外國營利事業銷售電子勞務予我國境內自然人者，該外國營利事業應自行報繳營業稅", "外國營利事業在中華民國境內銷售電子勞務予我國境內自然人者，應開立紙本發票", "外國國際運輸事業在中華民國境內有代理人者，其在我國境內載貨出境，應由代理人開立統一發票"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00300', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '經營農、林、漁、牧業之公司下列銷售貨物情形，何者應課徵營業稅？', '["向漁民購入漁產，切割、清洗後即行出售", "將自行生產玉米乾燥後即行出售", "將種植之牧草收割後即行出售", "將生產馬鈴薯製作薯條，冷凍後出售"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00301', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國A海運公司112年相關交易情形如下：①銷售國際運輸用之船舶  ②進口國際運輸用之船舶  ③進', '["銷售供漁船使用之機器設備之用油。以上何種銷售情形免徵 營業稅？", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
